using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;
using System.IO;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Collect all errors and warnings
var errors = new List<(string project, string file, int line, int col, string code, string message, string subcategory)>();
var warnings = new List<(string project, string file, int line, int col, string code, string message)>();
var projectResults = new Dictionary<string, bool>(); // project -> succeeded

build.VisitAllChildren<Error>(e => {
    var proj = GetProjectName(e);
    errors.Add((proj, e.File ?? "", e.LineNumber, e.ColumnNumber, e.Code ?? "", e.Text ?? "", e.Subcategory ?? ""));
});

build.VisitAllChildren<Warning>(w => {
    var proj = GetProjectName(w);
    warnings.Add((proj, w.File ?? "", w.LineNumber, w.ColumnNumber, w.Code ?? "", w.Text ?? ""));
});

build.VisitAllChildren<Project>(p => {
    projectResults[p.Name ?? p.ProjectFile ?? "unknown"] = p.Succeeded;
});

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Overall succeeded: {build.Succeeded}");
Console.WriteLine();

Console.WriteLine("=== PROJECT RESULTS ===");
foreach (var kvp in projectResults.OrderBy(x => x.Key))
{
    Console.WriteLine($"  [{(kvp.Value ? "OK" : "FAIL")}] {kvp.Key}");
}
Console.WriteLine();

Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
foreach (var g in errors.GroupBy(e => e.project))
{
    Console.WriteLine($"\n--- Project: {g.Key} ---");
    foreach (var e in g)
    {
        var location = string.IsNullOrEmpty(e.file) ? "" : $"{e.file}({e.line},{e.col})";
        Console.WriteLine($"  [{e.code}] {location}: {e.message}");
    }
}

Console.WriteLine($"\n=== WARNINGS ({warnings.Count}) ===");
foreach (var g in warnings.GroupBy(w => w.project).Take(10))
{
    Console.WriteLine($"\n--- Project: {g.Key} ---");
    foreach (var w in g.Take(5))
    {
        var location = string.IsNullOrEmpty(w.file) ? "" : $"{w.file}({w.line},{w.col})";
        Console.WriteLine($"  [{w.code}] {location}: {w.message}");
    }
    if (g.Count() > 5) Console.WriteLine($"  ... and {g.Count() - 5} more warnings");
}

static string GetProjectName(BaseNode node)
{
    var current = node;
    while (current != null)
    {
        if (current is Project p) return p.Name ?? p.ProjectFile ?? "unknown";
        current = current.Parent as BaseNode;
    }
    return "unknown";
}
