using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

var errors = new List<(string project, string file, int line, int col, string code, string message)>();
var warnings = new List<(string project, string file, int line, int col, string code, string message)>();

build.VisitAllChildren<Error>(e => {
    var proj = GetProjectName(e);
    errors.Add((proj, e.File ?? "", e.LineNumber, e.ColumnNumber, e.Code ?? "", e.Text ?? ""));
});

build.VisitAllChildren<Warning>(w => {
    var proj = GetProjectName(w);
    warnings.Add((proj, w.File ?? "", w.LineNumber, w.ColumnNumber, w.Code ?? "", w.Text ?? ""));
});

// Collect project info
var projects = new List<(string name, string projectFile, bool succeeded)>();
build.VisitAllChildren<Project>(p => {
    projects.Add((p.Name ?? "unknown", p.ProjectFile ?? "unknown", !HasDescendantError(p)));
});

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Overall succeeded: {build.Succeeded}");
Console.WriteLine();

Console.WriteLine("=== PROJECT RESULTS ===");
var uniqueProjects = projects.GroupBy(p => p.projectFile).Select(g => (name: g.First().name, file: g.Key, succeeded: g.Any(x => x.succeeded)));
foreach (var p in uniqueProjects.OrderBy(x => x.name))
{
    Console.WriteLine($"  [{(p.succeeded ? "OK" : "FAIL")}] {p.name} ({p.file})");
}
Console.WriteLine();

Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
foreach (var g in errors.GroupBy(e => e.project))
{
    Console.WriteLine($"\n--- Project: {g.Key} ---");
    foreach (var e in g)
    {
        var location = string.IsNullOrEmpty(e.file) ? "" : $"{e.file}({e.line},{e.col})";
        Console.WriteLine($"  [{e.code}] {location}: {e.message}");
    }
}

Console.WriteLine($"\n=== WARNINGS (showing up to 20 of {warnings.Count}) ===");
foreach (var g in warnings.GroupBy(w => w.project))
{
    Console.WriteLine($"\n--- Project: {g.Key} ({g.Count()} warnings) ---");
    foreach (var w in g.Take(5))
    {
        var location = string.IsNullOrEmpty(w.file) ? "" : $"{w.file}({w.line},{w.col})";
        Console.WriteLine($"  [{w.code}] {location}: {w.message}");
    }
    if (g.Count() > 5) Console.WriteLine($"  ... and {g.Count() - 5} more");
}

static string GetProjectName(BaseNode node)
{
    var current = node;
    while (current != null)
    {
        if (current is Project p) return p.Name ?? p.ProjectFile ?? "unknown";
        current = current.Parent as BaseNode;
    }
    return "unknown";
}

static bool HasDescendantError(BaseNode node)
{
    bool found = false;
    if (node is TreeNode tn)
    {
        if (node is Error) return true;
        if (tn.HasChildren)
        {
            foreach (var child in tn.Children)
            {
                if (child is BaseNode bn && HasDescendantError(bn)) { found = true; break; }
            }
        }
    }
    return found;
}
