                    if (ai is TreeNode tn && tn.HasChildren)
                    {
                        foreach (var child in tn.Children)
                        {
                            if (child is Item item)
                                Console.WriteLine($"    {ai.Name}: {item.Name}");
                        }
                    }
                }
            });
        }
    });
}

static string GetProjectName(BaseNode node)
{
    var current = node;
    while (current != null)
    {
        if (current is Project p) return p.Name ?? p.ProjectFile ?? "unknown";
        current = current.Parent as BaseNode;
    }
    return "unknown";
}
